import {useMemo} from 'react';
import {useKitsTheme} from '../Contexts/Theme';
import type {Severity, ISeverityColorSlots} from '@lmb/kitsconcerto-types';

export interface ResolvedSeverityColors {
    solid: string;
    bgTint: string;
    iconFg: string;
    iconBg: string;
    text: string;
    border: string;
}

/**
 * Resolves all severity color slots for a given severity using the current theme.
 * Returns platform-appropriate values (CSS vars on web, hex on native).
 * Handles dark mode by swapping shade levels for subtle tints.
 */
export function useSeverityColors(severity: Severity): ResolvedSeverityColors {
    const {theme, resolveToken, colorMode} = useKitsTheme();

    return useMemo(() => {
        const slots: ISeverityColorSlots = theme.severity?.[severity] ?? theme.severity?.secondary;
        if (!slots) {
            // Fallback if severity theme not configured
            const fallback = resolveToken('gray.500');
            return {solid: fallback, bgTint: fallback, iconFg: fallback, iconBg: fallback, text: fallback, border: fallback};
        }

        // Brand severity: solid/border/iconFg dynamically follow the primary token
        if (severity === 'brand') {
            const primary = resolveToken('primary');
            if (colorMode === 'dark') {
                const swapShade = (token: string, target: string) =>
                    resolveToken(token.replace(/\.\d+$/, `.${target}`));
                return {
                    solid: primary,
                    bgTint: swapShade(slots.solid, '900'),
                    iconFg: primary,
                    iconBg: swapShade(slots.solid, '800'),
                    text: swapShade(slots.solid, '200'),
                    border: primary,
                };
            }
            return {
                solid: primary,
                bgTint: resolveToken(slots.bgTint),
                iconFg: primary,
                iconBg: resolveToken(slots.iconBg),
                text: resolveToken(slots.text),
                border: primary,
            };
        }

        if (colorMode === 'dark') {
            // In dark mode, swap light shades for dark equivalents
            const swapShade = (token: string, target: string) => {
                return resolveToken(token.replace(/\.\d+$/, `.${target}`));
            };
            return {
                solid: resolveToken(slots.solid),
                bgTint: swapShade(slots.solid, '900'),
                iconFg: swapShade(slots.solid, '300'),
                iconBg: swapShade(slots.solid, '800'),
                text: swapShade(slots.solid, '200'),
                border: resolveToken(slots.border),
            };
        }

        return {
            solid: resolveToken(slots.solid),
            bgTint: resolveToken(slots.bgTint),
            iconFg: resolveToken(slots.iconFg),
            iconBg: resolveToken(slots.iconBg),
            text: resolveToken(slots.text),
            border: resolveToken(slots.border),
        };
    }, [theme.severity, severity, resolveToken, colorMode]);
}

/**
 * Returns the full resolved map for all severities.
 * Useful when a component needs to look up colors dynamically
 * (e.g., per-button severity in a buttons array).
 */
export function useAllSeverityColors(): Record<Severity, ResolvedSeverityColors> {
    const {theme, resolveToken, colorMode} = useKitsTheme();

    return useMemo(() => {
        const severities: Severity[] = ['success', 'info', 'warning', 'danger', 'help', 'secondary', 'brand'];
        const result = {} as Record<Severity, ResolvedSeverityColors>;
        const primary = resolveToken('primary');

        for (const key of severities) {
            const slots = theme.severity?.[key];
            if (!slots) continue;

            const isBrand = key === 'brand';

            if (colorMode === 'dark') {
                const swapShade = (token: string, target: string) => {
                    return resolveToken(token.replace(/\.\d+$/, `.${target}`));
                };
                result[key] = {
                    solid: isBrand ? primary : resolveToken(slots.solid),
                    bgTint: swapShade(slots.solid, '900'),
                    iconFg: isBrand ? primary : swapShade(slots.solid, '300'),
                    iconBg: swapShade(slots.solid, '800'),
                    text: swapShade(slots.solid, '200'),
                    border: isBrand ? primary : resolveToken(slots.border),
                };
            } else {
                result[key] = {
                    solid: isBrand ? primary : resolveToken(slots.solid),
                    bgTint: resolveToken(slots.bgTint),
                    iconFg: isBrand ? primary : resolveToken(slots.iconFg),
                    iconBg: resolveToken(slots.iconBg),
                    text: resolveToken(slots.text),
                    border: isBrand ? primary : resolveToken(slots.border),
                };
            }
        }

        return result;
    }, [theme.severity, resolveToken, colorMode]);
}
